1	const NEIGHBOR_OFFSETS: [number, number][] = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [0, -1],           [0, 1],
4	  [1, -1],  [1, 0],  [1, 1],
5	];
6	
7	export function nextGeneration(liveCells: [number, number][]): [number, number][] {
8	  const liveCellKeys = new Set(liveCells.map(([x, y]) => `${x},${y}`));
9	
10	  const isAlive = (x: number, y: number): boolean =>
11	    liveCellKeys.has(`${x},${y}`);
12	
13	  const countNeighbors = (x: number, y: number): number =>
14	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
15	
16	  const survivors = liveCells.filter(([x, y]) => {
17	    const count = countNeighbors(x, y);
18	    return count === 2 || count === 3;
19	  });
20	
21	  const deadCandidates = new Set<string>();
22	  for (const [x, y] of liveCells) {
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const key = `${x + dx},${y + dy}`;
25	      if (!liveCellKeys.has(key)) {
26	        deadCandidates.add(key);
27	      }
28	    }
29	  }
30	
31	  const born: [number, number][] = [];
32	  for (const key of deadCandidates) {
33	    const [x, y] = key.split(",").map(Number) as [number, number];
34	    if (countNeighbors(x, y) === 3) {
35	      born.push([x, y]);
36	    }
37	  }
38	
39	  return [...survivors, ...born];
40	}
